clc; clear; close all;

%% ==============================
% MODULE 4: SERVER / DASHBOARD
% ===============================

NODE_ID = 1;
current_status = "UNKNOWN";
last_packet_time = -inf;

event_log = strings(0,3); % [time, node, status]

offline_timeout = 5; % seconds

%% ---------- FIGURE ----------
figure('Color','w','Position',[200 100 1200 600]); %[output:9960a6e7]

% Status panel
subplot(2,2,1); axis off; %[output:9960a6e7]
hStatus = text(0.5,0.5,'','FontSize',22,... %[output:9960a6e7]
    'HorizontalAlignment','center','FontWeight','bold'); %[output:9960a6e7]

% Network panel
subplot(2,2,2); axis off; %[output:9960a6e7]
hNet = text(0.5,0.5,'','FontSize',16,... %[output:9960a6e7]
    'HorizontalAlignment','center'); %[output:9960a6e7]

% Event log panel
subplot(2,2,[3 4]); %[output:9960a6e7]
hTable = uitable('Units','normalized',... %[output:9960a6e7]
    'Position',[0.05 0.05 0.9 0.4],... %[output:9960a6e7]
    'ColumnName',{'Time','Node','Status'},... %[output:9960a6e7]
    'Data',{}); %[output:9960a6e7]

sgtitle('Module 4: Mine Safety Monitoring Dashboard','FontWeight','bold'); %[output:9960a6e7]

%% ---------- SIMULATED INPUT (FROM MODULE 3) ----------
% Example packets (normally received dynamically)

packets(1).time = 62; packets(1).node = 1; packets(1).status = "EMERGENCY";
packets(2).time = 80; packets(2).node = 1; packets(2).status = "EMERGENCY";
packets(3).time = 95; packets(3).node = 1; packets(3).status = "OFFLINE";

packet_idx = 1;

%% ---------- MAIN DASHBOARD LOOP ----------
for t = 0:120 %[output:group:5fb30fb1]

    % Simulate packet arrival
    if packet_idx <= length(packets) && packets(packet_idx).time == t
        pkt = packets(packet_idx);
        packet_idx = packet_idx + 1;

        current_status = pkt.status;
        last_packet_time = t;

        event_log(end+1,:) = [string(t), "Node " + pkt.node, pkt.status];
        hTable.Data = event_log;
    end

    % Offline detection
    if t - last_packet_time > offline_timeout
        current_status = "OFFLINE";
    end

    % ---- STATUS PANEL ----
    subplot(2,2,1); cla; axis off; %[output:9960a6e7]

    switch current_status
        case "NORMAL"
            col = 'g';
        case "WARNING"
            col = [0.9 0.6 0];
        case "EMERGENCY"
            col = 'r';
        otherwise
            col = [0.5 0.5 0.5];
    end

    rectangle('Position',[0.2 0.3 0.6 0.4],...
        'FaceColor',col,'Curvature',0.1);

    text(0.5,0.5,"STATUS: " + current_status,...
        'HorizontalAlignment','center',...
        'FontSize',20,'Color','w','FontWeight','bold');

    % ---- NETWORK PANEL ----
    subplot(2,2,2); cla; axis off; %[output:9960a6e7]

    text(0.5,0.6,"Last Packet Time: " + string(last_packet_time),...
        'HorizontalAlignment','center','FontSize',16);

    if current_status == "OFFLINE"
        text(0.5,0.4,"Node unreachable",'Color','r',...
            'HorizontalAlignment','center','FontSize',16);
    else
        text(0.5,0.4,"Link OK",'Color','g',...
            'HorizontalAlignment','center','FontSize',16);
    end

    drawnow;
    pause(0.2);
end %[output:group:5fb30fb1]


